import { DateView } from "@mui/x-date-pickers";
import { Dayjs } from "dayjs";
import { useState } from "react";

import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { StaticCalendar } from "./StaticCalendar.tsx";

type MonthPickerProps = {
  onMonthChange: (date: Dayjs) => void;
};

export function MonthPicker({ onMonthChange }: MonthPickerProps) {
  const { selectedDay, maxDateRangeFrom, maxDateRangeTo } =
    useTimePeriodControls();

  const [value, setValue] = useState<Dayjs | null>(selectedDay);
  const [view, setView] = useState<DateView>("month");

  return (
    <StaticCalendar
      value={value}
      view={view}
      sx={{
        "& .MuiDateCalendar-root": {
          height: "100%",
          minHeight: "260px",
        },
      }}
      onViewChange={setView}
      onChange={(val) => {
        setValue(val);
        if (view === "month" && val) {
          onMonthChange(val);
        }
      }}
      minDate={maxDateRangeFrom}
      maxDate={maxDateRangeTo}
      views={["year", "month"]}
      openTo="month"
    />
  );
}

import { PickersDay } from "@mui/x-date-pickers";
import type { PickersDayProps } from "@mui/x-date-pickers/PickersDay";
import { Dayjs } from "dayjs";
import type { ComponentType } from "react";
import { useState } from "react";

import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { StaticCalendar } from "./StaticCalendar.tsx";

type WeekPickerProps = {
  onWeekChange: (date: Dayjs) => void;
};

export function WeekPicker({ onWeekChange }: WeekPickerProps) {
  const { selectedDay, maxDateRangeFrom, maxDateRangeTo } =
    useTimePeriodControls();

  const [value, setValue] = useState<Dayjs | null>(selectedDay);
  const [view, setView] = useState<"year" | "month" | "day">("day");

  return (
    <StaticCalendar
      value={value}
      view={view}
      onViewChange={setView}
      sx={{
        "& .MuiDateCalendar-root": {
          height: "100%",
          minHeight: "354px",
        },
        "& .MuiPickersSlideTransition-root": {
          minHeight: "260px",
        },
      }}
      onChange={(val) => {
        setValue(val);
        if (view === "day" && val) {
          onWeekChange(val);
        }
      }}
      minDate={maxDateRangeFrom}
      maxDate={maxDateRangeTo}
      views={["year", "month", "day"]}
      showDaysOutsideCurrentMonth
      slots={{
        day: WeekPickerDay as ComponentType<PickersDayProps<Dayjs>>,
      }}
      slotProps={{
        day: {
          selectedDay: value,
          minDate: maxDateRangeFrom,
          maxDate: maxDateRangeTo,
        } as Record<string, unknown>,
      }}
    />
  );
}

type WeekPickerDayProps = PickersDayProps<Dayjs> & {
  selectedDay: Dayjs | null;
  minDate: Dayjs;
  maxDate: Dayjs;
};

/**
 * Custom day component that highlights the entire week row when in week view
 */
export function WeekPickerDay({
  day,
  selectedDay,
  minDate,
  maxDate,
  ...other
}: WeekPickerDayProps) {
  if (!selectedDay) {
    return <PickersDay {...other} day={day} />;
  }

  const startOfWeek = selectedDay.startOf("isoWeek");
  const endOfWeek = selectedDay.endOf("isoWeek");
  const isInSelectedWeek =
    day.isSame(startOfWeek, "day") ||
    (day.isAfter(startOfWeek) && day.isBefore(endOfWeek)) ||
    day.isSame(endOfWeek, "day");

  const isStartOfWeek = day.isSame(startOfWeek, "day");
  const isEndOfWeek = day.isSame(endOfWeek, "day");

  // Disable days outside the available range
  const isOutsideRange =
    day.isBefore(minDate, "day") || day.isAfter(maxDate, "day");

  return (
    <PickersDay
      {...other}
      day={day}
      disabled={isOutsideRange}
      disableMargin
      selected={isInSelectedWeek}
      sx={{
        padding: 2.5,
        ...(isInSelectedWeek && {
          backgroundColor: "primary.main",
          color: "primary.contrastText",
          borderRadius: 0,
          "&:hover": {
            backgroundColor: "primary.dark",
          },
          "&:focus": {
            backgroundColor: "primary.main",
          },
        }),
        ...(isStartOfWeek &&
          isInSelectedWeek && {
            borderTopLeftRadius: "50%",
            borderBottomLeftRadius: "50%",
          }),
        ...(isEndOfWeek &&
          isInSelectedWeek && {
            borderTopRightRadius: "50%",
            borderBottomRightRadius: "50%",
          }),
      }}
    />
  );
}

import type { BwCashflowModel } from "@dfp/bw-sdk-bw-cashflow";

import type { BalanceQuality } from "../../types/cashflow.types.ts";

export type CashFlowResponse =
  BwCashflowModel["getCashFlowAndBalanceStates"]["response"];
type CashFlowStates = NonNullable<CashFlowResponse["cashFlowStates"]>;
type SumArray = NonNullable<CashFlowStates["sumArray"]>;
type SumArrayItem = SumArray[number];
type IncomeCategorySum = NonNullable<SumArrayItem["incomeCategorySum"]>;
type ApiCategoryType = IncomeCategorySum[number]["category"];

export type CategoryType = ApiCategoryType;

/**
 * Represents a single period column in the cashflow table
 */
export type CashflowPeriod = {
  id: string;
  /** Date of the period (YYYY-MM-DD) */
  dateFrom: string;
  dateTo: string;
  /** Total income for this period */
  income: number;
  /** Total costs for this period */
  costs: number;
  /** Net change (income - costs) */
  netBalance: number;
  /** Final balance at end of period, including quality information when available */
  finalBalance: {
    value: number;
    balanceQuality: BalanceQuality;
  } | null;
  incomeCategories: Map<CategoryType, number>;
  costsCategories: Map<CategoryType, number>;
  progressPercentage?: number;
  transactionCount?: number;
};

/**
 * Complete data structure for the cashflow table
 */
export type CashflowTableData = {
  periods: CashflowPeriod[];
  granularity: "1D" | "1W" | "1M";
  categories: {
    income: CategoryType[];
    costs: CategoryType[];
  };
};

export type CategoryFilter = {
  income: CategoryType[];
  costs: CategoryType[];
};

export type CategoryFilterSection = "income" | "costs";

export type CategoryOption = {
  value: CategoryType;
  label: string;
};

export type CategoryFilterState = {
  categoryFilter: CategoryFilter;
  setCategoryFilter: (filter: CategoryFilter) => void;
  allCategories: CategoryOption[];
  allCategoryValues: CategoryType[];
  isFiltered: boolean;
  totalSelected: number;
  totalAvailable: number;
};

export type CashflowTableCellProps = {
  value: number;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  /** Optional progress percentage to display as a bar */
  progressPercentage?: number;
  /** Color mode for value display:
   * - "balance": red for negative, green for positive (Net Balance)
   * - "final": red for negative only, neutral for positive/zero (Final Balance)
   * - "none": always neutral color (Income, Costs, all categories)
   * Default: "none"
   */
  colorMode?: "balance" | "final" | "none";
  /** Optional click handler. When provided, replaces the default column toggle behavior. */
  onClick?: () => void;
};

