import { Box, Popover, ToggleButton, ToggleButtonGroup } from "@mui/material";
import { LocalizationProvider } from "@mui/x-date-pickers";
import { AdapterDayjs } from "@mui/x-date-pickers/AdapterDayjs";
import { Dayjs } from "dayjs";
import type { ComponentProps } from "react";

import { useTT } from "../../useTT.ts";
import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { Interval } from "../types/index.ts";
import { MonthPicker } from "./MonthPicker.tsx";
import { WeekPicker } from "./WeekPicker.tsx";

type CalendarPopoverProps = {
  onClose: () => void;
  calendarPickerView: Interval;
  onCalendarPickerViewChange: (view: Interval) => void;
} & Pick<ComponentProps<typeof Popover>, "open" | "anchorEl">;

export function CalendarPopover({
  open,
  onClose,
  anchorEl,
  calendarPickerView,
  onCalendarPickerViewChange,
}: CalendarPopoverProps) {
  const { tt } = useTT();
  const { setPeriod: selectDay } = useTimePeriodControls();

  const handleMonthSelect = (date: Dayjs) => {
    const newDate = date.startOf("month");
    selectDay(newDate, "1M");
    onClose();
  };

  const handleWeekSelect = (date: Dayjs) => {
    const firstDayOfWeek = date.startOf("isoWeek");
    selectDay(firstDayOfWeek, "1W");
    onClose();
  };

  return (
    <Popover
      open={open}
      anchorEl={anchorEl}
      onClose={() => onClose()}
      anchorOrigin={{
        vertical: "bottom",
        horizontal: "center",
      }}
      transformOrigin={{
        vertical: "top",
        horizontal: "center",
      }}
      slotProps={{
        paper: {
          sx: {
            borderRadius: 2,
            boxShadow: (theme) => theme.shadows[4],
          },
        },
      }}
    >
      <Box sx={{ padding: 3 }}>
        <ToggleButtonGroup
          value={calendarPickerView}
          exclusive
          onChange={(_, val) => {
            if (val) {
              onCalendarPickerViewChange(val);
            }
          }}
          size="small"
          variant="secondary"
          fullWidth
        >
          <ToggleButton value="1M">{tt("calendarPeriod.month")}</ToggleButton>
          <ToggleButton value="1W">{tt("calendarPeriod.week")}</ToggleButton>
        </ToggleButtonGroup>

        <LocalizationProvider dateAdapter={AdapterDayjs}>
          {calendarPickerView === "1M" ? (
            <MonthPicker onMonthChange={handleMonthSelect} />
          ) : (
            <WeekPicker onWeekChange={handleWeekSelect} />
          )}
        </LocalizationProvider>
      </Box>
    </Popover>
  );
}

